solution:
const mean = d => d.length ? d.reduce((a,b)=>a+b,0)/d.length : null;
const median = d => { if(!d.length) return null; const s=[...d].sort((a,b)=>a-b), m=Math.floor(s.length/2); return s.length%2 ? s[m] : (s[m-1]+s[m])/2; };
const mode = d => { if(!d.length) return null; const f={}; d.forEach(x=>f[x]=(f[x]||0)+1); const mc=Math.max(...Object.values(f)); return Object.keys(f).filter(k=>f[k]==mc).map(Number); };
